// 解析 Google News RSS XML
const rssData = $input.first().json;
let newsItems = [];

try {
  // RSS 格式處理
  if (rssData.rss && rssData.rss.channel) {
    const channel = rssData.rss.channel;
    const items = channel.item || [];

    newsItems = items.map(item => ({
      title: item.title || '',
      link: item.link || '',
      description: item.description?.replace(/<[^>]*>/g, '').substring(0, 300) || '',
      pubDate: item.pubDate || new Date().toISOString(),
      source: 'Google News'
    }));
  }
} catch (error) {
  console.error('RSS parsing error:', error);
}

return newsItems.map(item => ({ json: item }));

// 評估新聞與網站調性的相關性
const newsItem = $input.first().json;

const highPriorityKeywords = ['ChatGPT', 'GPT-4', 'Claude', 'AI 工具', '提示詞', '應用', '教學', '入門', '新手', '使用方法'];
const mediumPriorityKeywords = ['機器學習', '深度學習', '人工智慧', 'AI 技術', '研究', '發展'];
const lowPriorityKeywords = ['股票', '財報', '併購', '公司', '市場', '投資'];

let score = 50; // 基礎分

// 高優先級關鍵詞（+20）
highPriorityKeywords.forEach(keyword => {
  if (newsItem.title.includes(keyword) || newsItem.description.includes(keyword)) {
    score += 20;
  }
});

// 中優先級關鍵詞（+10）
mediumPriorityKeywords.forEach(keyword => {
  if (newsItem.title.includes(keyword) || newsItem.description.includes(keyword)) {
    score += 10;
  }
});

// 低優先級關鍵詞（-15）
lowPriorityKeywords.forEach(keyword => {
  if (newsItem.title.includes(keyword) || newsItem.description.includes(keyword)) {
    score -= 15;
  }
});

// 限制分數範圍
score = Math.max(0, Math.min(100, score));

// 判斷是否適合網站
const isSuitable = score >= 70;

return [{
  json: {
    ...newsItem,
    relevance_score: score,
    is_suitable: isSuitable,
    selected_category: score >= 80 ? '高分內容' : score >= 70 ? '中分內容' : '低分內容'
  }
}];

