const response = $input.first().json.choices[0].message.content;
const article = JSON.parse(response);

// 生成結構化內容
const content = `
## ${article.title}

### 📰 新聞背景
根據最新 AI 新聞報導，這項技術正在改變我們使用 AI 的方式...

### 生活痛點
${article.pain_point}

### 應用場景
${article.scenario}

### AI 解決方案
${article.solution}

### 簡單實例
#### ❌ 錯誤示範
${article.example?.wrong || ''}

#### ✅ 正確用法
${article.example?.right || ''}

### 實作步驟
${Array.from({length: 4}, (_, i) => `<li>第${i+1}步：根據新聞內容的實際應用方法</li>`).join('\n')}

### 常見問題
${article.faq?.map(f => `#### Q: ${f.question}\nA: ${f.answer}`).join('\n\n')}

### 💡 學習挑戰
試試看用今天學到的新技術，解決一個你日常遇到的問題！

### 總結
${article.summary || ''}
`;

return [{
  json: {
    category: article.category_suggestion || '生活應用',
    title: article.title,
    summary: article.summary || '',
    content: content,
    read_time: `${Math.ceil(content.length / 500)} 分鐘`,
    is_published: false, // 待審核狀態
    seo_title: article.seo_title || '',
    keywords: article.keywords || [],
    search_intent: article.search_intent || '',
    target_audience: article.target_audience || '',
    pain_point: article.pain_point || '',
    scenario: article.scenario || '',
    solution: article.solution || '',
    example: article.example || null,
    faq: article.faq || [],
    semantic_tags: [...(article.semantic_tags || []), 'AI新聞', '最新技術'],
    difficulty_level: article.difficulty_level || 2,
    ai_generated: true,
    news_source_link: $input.first().json.link,
    relevance_score: $input.first().json.relevance_score,
    created_at: new Date().toISOString(),
    published_at: new Date().toISOString()
  }
}];

const article = $input.first().json;
const validation = {
  valid: true,
  warnings: [],
  errors: []
};

// 必填欄位檢查
const requiredFields = ['title', 'seo_title', 'keywords', 'pain_point', 'scenario', 'solution', 'example', 'faq'];
requiredFields.forEach(field => {
  if (!article[field] || (Array.isArray(article[field]) && article[field].length === 0)) {
    validation.errors.push(`缺少必填欄位: ${field}`);
    validation.valid = false;
  }
});

// 內容長度檢查
if (article.content?.length < 500) {
  validation.warnings.push('內容長度較短（<500字）');
}

// FAQ 數量檢查
if (article.faq?.length < 3) {
  validation.warnings.push('FAQ 數量少於 3 組');
}

// 關鍵詞檢查
if (article.keywords?.length < 3) {
  validation.warnings.push('關鍵詞少於 3 個');
}

return [{
  json: {
    ...article,
    validation: validation,
    validation_passed: validation.valid
  }
}];

// 統計本次執行的結果
const allInputs = $input.all();
const savedArticles = allInputs.filter(item => item.json.id).length;

return [{
  json: {
    summary: {
      total_processed: allInputs.length,
      articles_saved: savedArticles,
      timestamp: new Date().toISOString(),
      status: savedArticles > 0 ? 'success' : 'no_new_content'
    }
  }
}];
